var config = ManualConfig.Create(DefaultConfig.Instance)
    .AddJob(Job.Default
        .WithRuntime(CoreRuntime.Core90)
        .WithToolchain(CsProjCoreToolchain.NetCoreApp90))
    .AddJob(Job.Default
        .WithRuntime(CoreRuntime.CreateForNewVersion("net10.0", ".NET 10.0"))
        .WithToolchain(CsProjCoreToolchain.From(new NetCoreAppSettings("net10.0", null, ".NET 10.0"))));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a representative text corpus (~1000 words)
        var words = new List<string>();
        var rng = new Random(42);
        string[] vocabulary =
        [
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "performance", "benchmarking", "optimization", "infrastructure",
            "a", "an", "is", "it", "to", "of", "and", "in",
            "extraordinarily", "simultaneously", "characteristics", "implementation",
            "go", "do", "up", "no", "on", "at", "be", "we",
            "internationalization", "conceptualization", "misunderstanding"
        ];
        for (int i = 0; i < 1000; i++)
            words.Add(vocabulary[rng.Next(vocabulary.Length)]);
        _analyzer = new TextAnalyzer(string.Join(" ", words));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

toolArgs.new_str:
using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Build a representative text corpus (~1000 words)
var words = new List<string>();
var rng = new Random(42);
string[] vocabulary =
[
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "performance", "benchmarking", "optimization", "infrastructure",
    "a", "an", "is", "it", "to", "of", "and", "in",
    "extraordinarily", "simultaneously", "characteristics", "implementation",
    "go", "do", "up", "no", "on", "at", "be", "we",
    "internationalization", "conceptualization", "misunderstanding"
];
for (int i = 0; i < 1000; i++)
    words.Add(vocabulary[rng.Next(vocabulary.Length)]);

var analyzer = new TextAnalyzer(string.Join(" ", words));

const int warmupIterations = 500;
const int measuredIterations = 5000;
const int runs = 5;

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Warmup: {warmupIterations}  |  Measured: {measuredIterations}  |  Runs: {runs}");
Console.WriteLine(new string('-', 70));

Benchmark("AverageWordLength", () => analyzer.AverageWordLength());
Benchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Benchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void Benchmark(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < warmupIterations; i++)
        action();

    var timings = new double[runs];
    for (int r = 0; r < runs; r++)
    {
        // Force GC before each run for consistency
        GC.Collect();
        GC.WaitForPendingFinalizers();
        GC.Collect();

        var sw = Stopwatch.StartNew();
        for (int i = 0; i < measuredIterations; i++)
            action();
        sw.Stop();
        timings[r] = sw.Elapsed.TotalNanoseconds / measuredIterations;
    }

    Array.Sort(timings);
    double median = timings[runs / 2];
    double min = timings[0];
    double max = timings[^1];

    Console.WriteLine($"{name,-25} median: {FormatNs(median),12}  |  min: {FormatNs(min),12}  |  max: {FormatNs(max),12}");
}

static string FormatNs(double ns)
{
    if (ns < 1_000) return $"{ns:F1} ns";
    if (ns < 1_000_000) return $"{ns / 1_000:F2} μs";
    return $"{ns / 1_000_000:F2} ms";
}

